type State = 'IDLE' | 'RUNNING' | 'COMPLETED';

export class WorkflowEngine {
  private state: State = 'IDLE';
  private subscribers: Set<(state: string) => void> = new Set();

  async trigger(transition: string, _payload: unknown): Promise<void> {
    if (transition === 'start' && this.state === 'IDLE') {
      this.state = 'RUNNING';
      this.notifySubscribers();
    } else if (transition === 'complete' && this.state === 'RUNNING') {
      this.state = 'COMPLETED';
      this.notifySubscribers();
    }
  }

  getState(): string {
    return this.state;
  }

  subscribe(callback: (state: string) => void): void {
    this.subscribers.add(callback);
  }

  private notifySubscribers(): void {
    for (const callback of this.subscribers) {
      callback(this.state);
    }
  }
}","filePath":"/home/zzwf/shared/agent-container/workspace/RL/just-oc/autoresearch/test/backend_developer_worker/run-20260408-234834-5/src/server/workflow/engine.ts"},"output":"Wrote file successfully.","metadata":{"diagnostics":{},"filepath":"/home/zzwf/shared/agent-container/workspace/RL/just-oc/autoresearch/test/backend_developer_worker/run-20260408-234834-5/src/server/workflow/engine.ts","exists":true,"truncated":false},"title":"autoresearch/test/backend_developer_worker/run-20260408-234834-5/src/server/workflow/engine.ts","time":{"start":1775692403153,"end":1775692403159}}}}
